head.script:
//-------------------------------------------------------------------------
// 변동사항
// 수입 상차 요청 승인 버튼 삭제 -> 화면 삭제 조치에 따름
// 이외 그리드 더블 클릭시에도 연결되었으나 연결부분 모두 삭제 처리 됨, 코드에 주석처리로 남겨 놓았음.
//-------------------------------------------------------------------------

//-------------------------------------------------------------------------
// 전역변수
//-------------------------------------------------------------------------
// Popup Check용 Hidden 값
scwin.hid_srchCopCoCd = ""; // 자가운송
scwin.hid_doorCd = "";      // Door
scwin.chk_admitClsCd = "";  // Check 승인여부
scwin.chk_rowCount = "";    // Check 승인여부
scwin.hid_LineCd = "";      // Line

// 호출 페이지에서 받는 파라미터, 페이지 로드에서 재할당
scwin.params = "";
scwin.blNoTrans = "";
scwin.lineTrans = "";


scwin.MSG_SD_INF_001 = "수출입 구분을 선택하십시오";
scwin.nowDt = WebSquare.date.getCurrentServerDate();  // 서버를 기준으로 현재 날짜 반환

//-------------------------------------------------------------------------
// 화면 로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function() {
// 호출 페이지 파라미터 Json 방식    
// scwin.params = $c.data.getParameter(); 
// scwin.blNoTrans = scwin.params.blNoTrans;
// scwin.lineTrans = scwin.params.lineTrans;



// 호출 페이지 파라미터 배열 방식    
scwin.params = $p.getAllParameter().paramData; // 배열 방식, 꺼낼땐 scwin.params[0]
scwin.blNoTrans = scwin.params[0];
// scwin.blNoTrans = "12345";
scwin.lineTrans = scwin.params[1];

    $c.sbm.execute(sbm_srchPickUp);

    const codeOptions = [
        { grpCd: "OP206", compID: "acb_srchPickupRgnCd" , opt : {"range" : "1"}}, // 셀렉트
        { grpCd: "SD060", compID: "acb_srchImpExpCls" }, // 수출입구분
        { grpCd: "OP179", compID: "acb_srchAdmitClsCd, gr_onReqInfo:admitClsCd" }, // 승인구분
        { grpCd: "OP611", compID: "acb_siteLine" }, // 셀렉트
        { grpCd: "SD144", compID: "gr_onReqInfo:mcomAssgnClsCd" }, // 셀렉트
    ];
    $c.data.setCommonCode(codeOptions);

    lc_dpctYn.setValue("");
    //PickUp 지역, 수입/수출 디폴트값 셋팅


    acb_srchPickupRgnCd.setValue("PUS");
    acb_srchPickupRgnCd.setDisabled(true);
    acb_srchImpExpCls.setDisabled(true);



    // scwin.udcOnComplete();

};

//-------------------------------------------------------------------------
// 화면 로딩시
//-------------------------------------------------------------------------
scwin.ondataload = function() {
    acb_srchPickupRgnCd.setValue("PUS");

}

//-------------------------------------------------------------------------
// 기본 날짜 세팅
//-------------------------------------------------------------------------
setTimeout (scwin.onUdcCompleted = function() {
    udc_srchDate.setInitDate(scwin.nowDt, scwin.nowDt);
    ed_srchBlBkNo.setValue(scwin.blNoTrans);
}, 150);

//-------------------------------------------------------------------------
// 대문자 변환
//-------------------------------------------------------------------------
scwin.onkeyup = function (e) {
    this.setValue(e.target.value.toUpperCase());
};



//-------------------------------------------------------------------------
// 조회 f_Retrieve
//-------------------------------------------------------------------------
scwin.btn_retrieve_onClick = async function (e) {
    if(! await $c.gus.cfValidate(udc_srchDate)) {
        return;
        }

    if(! await $c.gus.cfIsAfterDate(ica_srchFromDate.getValue(), ica_srchToDate.getValue())) {
        $c.win.alert(MSG_CM_ERR_039); // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
        ica_srchFromDate.focus();
        return;
    }

    if(ed_srchBlBkNo.getValue() != "" && acb_srchImpExpCls.getValue() == "") {
        $c.win.alert(MSG_SD_INF_001);
        return;
    }

    if(! await $c.gus.cfValidate([tb_srchCond]) )
        return;

    dma_srchCond.set("stDt", ica_srchFromDate.getValue());
    dma_srchCond.set("endDt", ica_srchToDate.getValue());
    dma_srchCond.set("blNo", ed_srchBlBkNo.getValue());
    dma_srchCond.set("odrNo", ed_srchOdrNo.getValue());
    dma_srchCond.set("mrn", ed_mrn.getValue());		
    dma_srchCond.set("msn", ed_msn.getValue());				
    dma_srchCond.set("hsn", ed_hsn.getValue());

    dma_srchCond.set("pickuprgnCd", acb_srchPickupRgnCd.getValue());
    dma_srchCond.set("impExpClsCd", acb_srchImpExpCls.getValue());
    dma_srchCond.set("admitClsCd", acb_srchAdmitClsCd.getValue());
    dma_srchCond.set("selfTransClntNo", ed_srchCopCoCd.getValue());
    dma_srchCond.set("lineCd", acb_siteLine.getValue());
    dma_srchCond.set("doorRgnCd", ed_doorCd.getValue());
    dma_srchCond.set("dpctClsCd", lc_dpctYn.getValue());


    $c.sbm.execute(sbm_retrieveOnRequestInfo)    


};

//-------------------------------------------------------------------------
// 데이터 조회 완료시
//-------------------------------------------------------------------------
scwin.ds_onReqInfo_ondataload = function () {
    let rowCnt = ds_onReqInfo.getTotalRow();

    if(rowCnt == 0) {
        $c.win.alert(MSG_CM_ERR_003);
    }

    spa_totalRows.setValue(rowCnt);

};


//-------------------------------------------------------------------------
// 조회 조건 초기화
//-------------------------------------------------------------------------
scwin.btn_fieldClear_onClick = function (e) {

    $c.gus.cfInitObjects([ica_srchFromDate,ica_srchToDate,ed_srchBlBkNo,ed_srchCopCoCd,ed_srchCopCoNm,ed_srchOdrNo,acb_siteLine,ed_doorCd,ed_doorNm])
    // $c.gus.cfInitObjects(tb_srchCond, null);

    acb_srchPickupRgnCd.setSelectedIndex(0);



};



//-------------------------------------------------------------------------
// 수입/수출 상차 요청 접수 등록 f_RegistOnReq
//-------------------------------------------------------------------------
scwin.btn_RegistOnReq_onClick = function (e) {
    let param = {
        selfTransClntNo         : ds_onReqInfo.getCellData(ds_onReqInfo.getRowPosition(), "selfTransClntNo"),
        onReqNo                 : ds_onReqInfo.getCellData(ds_onReqInfo.getRowPosition(), "onReqNo"),
        selfTransClntNm         : ds_onReqInfo.getCellData(ds_onReqInfo.getRowPosition(), "selfTransClntNm"),
        lineCd                  : ds_onReqInfo.getCellData(ds_onReqInfo.getRowPosition(), "lineCd")
    }

    let option = {

    }

    if(ds_onReqInfo.getCellData(ds_onReqInfo.getRowPosition(),"impExpClsCd")=="I"){

        // $c.win.openMenu("si_301_02_04b.xml", "/ui/ds/op/wrkrslts/cywrkrslts/si_301_02_04b.xml", "수입 상차요청 승인", param, option)

    } else if(ds_onReqInfo.getCellData(ds_onReqInfo.getRowPosition(),"impExpClsCd") == "O"){

        $c.win.openMenu("op_301_02_05b.xml", "/ui/ds/op/wrkrslts/cywrkrslts/op_301_02_05b.xml", "수출 상차요청 승인", param, option)
        // cfTabMenuUpdate("/ds/op/wrkrslts/cywrkrslts/op_301_02_05b.jsp?"+param, "수출 상차요청 승인");		

    }
};



//-------------------------------------------------------------------------
// UDC 공통 팝업 (자사 운송사)
//-------------------------------------------------------------------------
scwin.udc_srchCopCo_onClick = async function (e) {
    let pWhere = ",LOGISCLNT2";

    udc_srchCopCo.cfCommonPopUp(scwin.udc_srchCopCo_callBackFunc
    ,"" //ed_srchCopCoCd.getValue()
    ,"" //ed_srchCopCoNm.getValue()
    ,null
    ,null
    ,null
    ,null
    ,null
    ,pWhere
    ,null
    ,null
    ,null
    ,null
    ,null
    ,null
    ,null
    ,null);
};

scwin.udc_srchCopCo_onblurCode = async function (e) {
    let pWhere = ",LOGISCLNT2";

    if(ed_srchCopCoCd.getValue() != "") {
        udc_srchCopCo.cfCommonPopUp(scwin.udc_srchCopCo_callBackFunc
        , ed_srchCopCoCd.getValue() 
        ,""
        ,"T"
        ,null
        ,null
        ,null
        ,null
        ,pWhere
        ,null
        ,null
        ,null
        ,null
        ,null
        ,null
        ,null
        ,null);
    }else {
        ed_srchCopCoCd.setValue("");
        ed_srchCopCoNm.setValue("");
        return;
    }
};

scwin.udc_srchCopCo_onChangeName = async function (info) {
    let pWhere = ",LOGISCLNT2";
    if(ed_srchCopCoNm.getValue() != "") {
        udc_srchCopCo.cfCommonPopUp(scwin.udc_srchCopCo_callBackFunc
        , ""
        ,ed_srchCopCoNm.getValue()
        ,"T"
        ,null
        ,null
        ,null
        ,null
        ,pWhere
        ,null
        ,null
        ,null
        ,null
        ,null
        ,null
        ,null
        ,null);
    } else {
        ed_srchCopCoCd.setValue("");
        ed_srchCopCoNm.setValue("");
        return;
    }
};

//-------------------------------------------------------------------------
// UDC 공통 팝업 콜백(자사 운송사)
//-------------------------------------------------------------------------
scwin.udc_srchCopCo_callBackFunc = function(ret) {
        $c.gus.cfSetReturnValue(ret, ed_srchCopCoCd, ed_srchCopCoNm)
}

//-------------------------------------------------------------------------
// UDC 공통 팝업 (Door 지역)
//-------------------------------------------------------------------------
scwin.udc_door_onClick = async function (e) {

    let impExpClsCd = acb_srchImpExpCls.getValue();
    let pickuprgnCd = acb_srchPickupRgnCd.getValue();
    let stDt = ica_srchFromDate.getValue();
    let endDt = ica_srchToDate.getValue();

    let paramList = impExpClsCd + "," + pickuprgnCd + "," + stDt + "," + endDt

    udc_door.cfCommonPopUp(scwin.udc_door_callBackFunc
    , ed_doorCd.getValue()
    ,ed_doorNm.getValue()
    ,"T"
    ,null
    ,null
    ,null
    ,null
    ,paramList
    ,null
    ,null
    ,null
    ,null
    );
};

scwin.udc_door_onblurCode = async function (e) {
    if(ed_doorCd.getValue() != "") {

        let impExpClsCd = acb_srchImpExpCls.getValue();
        let pickuprgnCd = acb_srchPickupRgnCd.getValue();
        let stDt = ica_srchFromDate.getValue();
        let endDt = ica_srchToDate.getValue();

        let paramList = impExpClsCd + "," + pickuprgnCd + "," + stDt + "," + endDt

        udc_door.cfCommonPopUp(scwin.udc_door_callBackFunc
        , ed_doorCd.getValue() 
        ,""
        ,"T"
        ,null
        ,null
        ,null
        ,null
        ,paramList
        ,null
        ,null
        ,null
        ,null);
    }else {
        ed_doorCd.setValue("");
        ed_doorNm.setValue("");
        return;
    }
};

//-------------------------------------------------------------------------
// UDC 공통 팝업 콜백(Door 지역)
//-------------------------------------------------------------------------
scwin.udc_door_callBackFunc = function(ret) {
        $c.gus.cfSetReturnValue(ret, ed_doorCd, ed_doorNm)
}

//-------------------------------------------------------------------------
// UDC 공통 팝업 (B/L)
//-------------------------------------------------------------------------
scwin.udc_srchBl_onClick = async function (e) {
    if(acb_srchImpExpCls.getValue() == "") {
        $c.win.alert(scwin.MSG_SD_INF_001);
    }


    let impExpClsCd = acb_srchImpExpCls.getValue();
    let pickuprgnCd = acb_srchPickupRgnCd.getValue();
    let stDt = ica_srchFromDate.getValue();
    let endDt = ica_srchToDate.getValue();

    let paramList = impExpClsCd + "," + pickuprgnCd + "," + stDt + "," + endDt

    udc_srchBl.cfCommonPopUp(scwin.udc_srchBl_callBackFunc
    , ed_srchBlBkNo.getValue()
    ,""
    ,null
    ,null
    ,null
    ,null
    ,null
    ,paramList
    ,null
    ,null
    ,null
    ,null
    ,null
    ,null
    ,null
    ,null);
};

scwin.udc_srchBl_onblurCode = async function (e) {

    let impExpClsCd = acb_srchImpExpCls.getValue();
    let pickuprgnCd = acb_srchPickupRgnCd.getValue();
    let stDt = ica_srchFromDate.getValue();
    let endDt = ica_srchToDate.getValue();

    let paramList = impExpClsCd + "," + pickuprgnCd + "," + stDt + "," + endDt

    if(ed_doorCd.getValue() != "") {
        udc_srchBl.cfCommonPopUp(scwin.udc_srchBl_callBackFunc
        , ed_doorCd.getValue() 
        ,""
        ,null
        ,null
        ,null
        ,null
        ,null
        ,paramList
        ,null
        ,null
        ,null
        ,null
        ,null
        ,null
        ,null
        ,null);
    }else {
        return;
    }
};

//-------------------------------------------------------------------------
// UDC 공통 팝업 콜백(B/L)
//-------------------------------------------------------------------------
scwin.udc_srchBl_callBackFunc = function(ret) {
    if(ret != null) {
        ed_srchBlBkNo.setValue(ret[0]);
    } else {
        ed_srchBlBkNo.setValue("");
    }
}


//-------------------------------------------------------------------------
// 그리드 수출입 decode
//-------------------------------------------------------------------------
scwin.gr_impExpClsCd = function(data) {
    return $c.gus.decode(data, 
        "I", "수입",
        "O", "수출", ""
    );

}

//-------------------------------------------------------------------------
// 그리드 BL decode
//-------------------------------------------------------------------------
scwin.gr_bookingNo = function(data) {
    return $c.gus.decode(data, 
        "I", "blNo",
        "O", "bookingNo", ""
    );

}

//-------------------------------------------------------------------------
// 그리드 더블 클릭
//-------------------------------------------------------------------------
scwin.gr_onReqInfo_oncelldblclick = function (rowIndex, columnIndex, columnId) {

    if(rowIndex >= 0) {

        let param = {
            selfTransClntNo : ds_onReqInfo.getCellData(ds_onReqInfo.getRowPosition(), "selfTransClntNo"),
            onReqNo : ds_onReqInfo.getCellData(ds_onReqInfo.getRowPosition(), "onReqNo"),
            selfTransClntNm : ds_onReqInfo.getCellData(ds_onReqInfo.getRowPosition(), "selfTransClntNm"),
            lineCd : ds_onReqInfo.getCellData(ds_onReqInfo.getRowPosition(), "lineCd"),
            reqClntNo : ds_onReqInfo.getCellData(rowIndex, "reqClntNo")
        };

        if(columnId != "reqClntNm") {
            if(ds_onReqInfo.getCellData(ds_onReqInfo.getRowPosition(), "impExpClsCd") == "I") {
                // if(ds_onReqInfo.getCellData(ds_onReqInfo.getRowPosition(), "lineCd") == "TSL") {
                //     param.mrn = dma_srchCond.get("mrn"),
                //     param.msn = dma_srchCond.get("msn"),
                //     param.hsn = dma_srchCond.get("hsn"),
                //     param.blNo = dma_srchCond.get("blNo")

                //     $c.win.openMenu("수입 상차요청 승인", "/ui/ds/op/wrkrslts/cywrkrslts/si_301_02_04b.xml", "si_301_02_04b.xml", param);
                // } else {
                //     $c.win.openMenu("수입 상차요청 승인", "/ui/ds/op/wrkrslts/cywrkrslts/si_301_02_04b.xml", "si_301_02_04b.xml", param);
                // }
            } else {
                $c.win.openMenu("수출 상차요청 승인", "/ui/ds/op/wrkrslts/cywrkrslts/op_301_02_05b.xml", "op_301_02_05b.xml", param);
            }
        } else {

            $c.win.openMenu("화주별 운송사 현황", "/ui/ds/op/wrkrslts/cywrkrslts/op_301_02_30b.xml", "op_301_02_30b.xml", param);


        }
    }

};
